1	import { useState, type JSX } from 'react';
2	import type { TFunction } from 'i18next';
3	import { useTranslation } from 'react-i18next';
4	import type { Element } from '@bim-ai/core';
5	
6	import { BUILT_IN_FAMILIES, getFamilyById, getTypeById } from '../families/familyCatalog';
7	
8	import { planViewGraphicsMatrixRows, viewTemplateGraphicsMatrixRows } from '../plan/planProjection';
9	import { PlanViewGraphicsMatrix } from './PlanViewGraphicsMatrix';
10	import {
11	  SavedViewTagGraphicsAuthoring,
12	  SavedViewTemplateGraphicsAuthoring,
13	} from './savedViewTagGraphicsAuthoring';
14	
15	/**
16	 * Inspector parameter renderers — spec §13.
17	 *
18	 * Read-only field panels per element kind. The Apply / Reset footer is
19	 * left to the controlling Inspector component (which only shows it when
20	 * dirty=true). Numeric writes through the engine command pipeline land
21	 * separately when the redesigned palette gains drawing flow.
22	 */
23	
24	interface FieldRowProps {
25	  label: string;
26	  value: string;
27	  mono?: boolean;
28	}
29	
30	export function FieldRow({ label, value, mono }: FieldRowProps): JSX.Element {
31	  return (
32	    <div className="flex items-center justify-between gap-4 border-b border-border py-1.5 last:border-b-0">
33	      <span className="text-xs text-muted">{label}</span>
34	      <span className={['text-sm text-foreground', mono ? 'font-mono text-xs' : ''].join(' ')}>
35	        {value}
36	      </span>
37	    </div>
38	  );
39	}
40	
41	function fmtMm(value: number | null | undefined): string {
42	  if (value == null || !Number.isFinite(value)) return '—';
43	  if (Math.abs(value) >= 1000) return `${(value / 1000).toFixed(2)} m`;
44	  return `${value.toFixed(0)} mm`;
45	}
46	
47	export function InspectorPropertiesFor(el: Element, t: TFunction): JSX.Element {
48	  const f = (key: string) => t(`inspector.fields.${key}`);
49	  switch (el.kind) {
50	    case 'wall':
51	      return (
52	        <div>
53	          <FieldRow label={f('type')} value="Generic — wall" />
54	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
55	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
56	          <FieldRow label={f('level')} value={el.levelId} mono />
57	          <FieldRow label={f('start')} value={`${fmtMm(el.start.xMm)} · ${fmtMm(el.start.yMm)}`} mono />
58	          <FieldRow label={f('end')} value={`${fmtMm(el.end.xMm)} · ${fmtMm(el.end.yMm)}`} mono />
59	        </div>
60	      );
61	    case 'door':
62	      return (
63	        <div>
64	          <FieldRow label={f('family')} value={el.familyTypeId ?? 'Generic 900 × 2100'} mono />
65	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
66	          <FieldRow label={f('wall')} value={el.wallId} mono />
67	          <FieldRow label={f('alongT')} value={el.alongT.toFixed(3)} mono />
68	        </div>
69	      );
70	    case 'window':
71	      return (
72	        <div>
73	          <FieldRow label={f('family')} value={el.familyTypeId ?? 'Generic 1200 × 1500'} mono />
74	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
75	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
76	          <FieldRow label={f('sillHeight')} value={fmtMm(el.sillHeightMm)} />
77	          <FieldRow label={f('wall')} value={el.wallId} mono />
78	        </div>
79	      );
80	    case 'floor':
81	      return (
82	        <div>
83	          <FieldRow label={f('type')} value={el.floorTypeId ?? 'Generic 220 mm slab'} mono />
84	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
85	          <FieldRow label={f('structureThickness')} value={fmtMm(el.structureThicknessMm)} />
86	          <FieldRow label={f('finishThickness')} value={fmtMm(el.finishThicknessMm)} />
87	          <FieldRow label={f('level')} value={el.levelId} mono />
88	          <FieldRow label={f('boundaryPoints')} value={String(el.boundaryMm.length)} />
89	        </div>
90	      );
91	    case 'roof':
92	      return (
93	        <div>
94	          <FieldRow label={f('type')} value={el.roofTypeId ?? 'Generic gable'} mono />
95	          <FieldRow label={f('slope')} value={`${(el.slopeDeg ?? 0).toFixed(1)}°`} />
96	          <FieldRow label={f('overhang')} value={fmtMm(el.overhangMm)} />
97	          <FieldRow label={f('referenceLevel')} value={el.referenceLevelId} mono />
98	          <FieldRow label={f('footprintPoints')} value={String(el.footprintMm.length)} />
99	        </div>
100	      );
101	    case 'stair':
102	      return (
103	        <div>
104	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
105	          <FieldRow label={f('riser')} value={fmtMm(el.riserMm)} />
106	          <FieldRow label={f('tread')} value={fmtMm(el.treadMm)} />
107	          <FieldRow label={f('baseLevel')} value={el.baseLevelId} mono />
108	          <FieldRow label={f('topLevel')} value={el.topLevelId} mono />
109	        </div>
110	      );
111	    case 'room':
112	      return (
113	        <div>
114	          <FieldRow label={f('programme')} value={el.programmeCode ?? '—'} />
115	          <FieldRow label={f('department')} value={el.department ?? '—'} />
116	          <FieldRow label={f('function')} value={el.functionLabel ?? '—'} />
117	          <FieldRow label={f('finishSet')} value={el.finishSet ?? '—'} />
118	          <FieldRow label={f('level')} value={el.levelId} mono />
119	          <FieldRow label={f('outlinePoints')} value={String(el.outlineMm.length)} />
120	        </div>
121	      );
122	    case 'level':
123	      return (
124	        <div>
125	          <FieldRow label={f('elevation')} value={fmtMm(el.elevationMm)} />
126	          <FieldRow label={f('datumKind')} value={el.datumKind ?? '—'} mono />
127	        </div>
128	      );
129	    case 'section_cut':
130	      return (
131	        <div>
132	          <FieldRow
133	            label={f('lineStart')}
134	            value={`${fmtMm(el.lineStartMm.xMm)} · ${fmtMm(el.lineStartMm.yMm)}`}
135	            mono
136	          />
137	          <FieldRow
138	            label={f('lineEnd')}
139	            value={`${fmtMm(el.lineEndMm.xMm)} · ${fmtMm(el.lineEndMm.yMm)}`}
140	            mono
141	          />
142	          <FieldRow label={f('cropDepth')} value={fmtMm(el.cropDepthMm)} />
143	        </div>
144	      );
145	    case 'plan_view':
146	      return (
147	        <div>
148	          <FieldRow label={f('level')} value={el.levelId} mono />
149	          <FieldRow label={f('presentation')} value={el.planPresentation ?? 'default'} />
150	          {el.viewTemplateId ? <FieldRow label={f('template')} value={el.viewTemplateId} mono /> : null}
151	          {el.underlayLevelId ? <FieldRow label={f('underlay')} value={el.underlayLevelId} mono /> : null}
152	        </div>
153	      );
154	    case 'viewpoint':
155	      return (
156	        <div>
157	          <FieldRow label={f('name')} value={el.name} />
158	          <FieldRow label={f('id')} value={el.id} mono />
159	        </div>
160	      );
161	    case 'view_template':
162	      return (
163	        <div>
164	          <FieldRow label={f('scale')} value={el.scale} mono />
165	          {el.planDetailLevel ? <FieldRow label={f('detailLevel')} value={el.planDetailLevel} /> : null}
166	        </div>
167	      );
168	    default:
169	      return <p className="text-sm text-muted">{t('inspector.noParams', { kind: el.kind })}</p>;
170	  }
171	}
