216	export function InspectorGraphicsFor({
217	  el,
218	  elementsById,
219	  revision,
220	  onPersistProperty,
221	}: {
222	  el: Element;
223	  elementsById: Record<string, Element>;
224	  revision: number;
225	  onPersistProperty: (key: string, value: string) => void;
226	}): JSX.Element | null {
227	  if (el.kind === 'plan_view') {
228	    const rows = planViewGraphicsMatrixRows(elementsById, el.id);
229	    return (
230	      <div className="flex flex-col gap-4">
231	        <PlanViewGraphicsMatrix rows={rows} />
232	        <SavedViewTagGraphicsAuthoring
233	          variant="plan_view"
234	          selected={el as Extract<Element, { kind: 'plan_view' }>}
235	          revision={revision}
236	          elementsById={elementsById}
237	          onPersistProperty={onPersistProperty}
238	        />
239	      </div>
240	    );
241	  }
242	  if (el.kind === 'view_template') {
243	    const rows = viewTemplateGraphicsMatrixRows(elementsById, el.id);
244	    return (
245	      <div className="flex flex-col gap-4">
246	        <PlanViewGraphicsMatrix
247	          rows={rows}
248	          footnote="Template defaults — plan_view overrides these when linked."
249	        />
250	        <SavedViewTemplateGraphicsAuthoring
251	          selected={el as Extract<Element, { kind: 'view_template' }>}
252	          revision={revision}
253	          elementsById={elementsById}
254	          onPersistProperty={onPersistProperty}
255	        />
256	      </div>
257	    );
258	  }
259	  return null;
260	}
