262	const INPUT_CLS =
263	  'mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]';
264	const LABEL_CLS = 'block text-[10px] text-muted';
265	
266	/** Editable inspector for plan_view elements (Properties tab). */
267	export function InspectorPlanViewEditor({
268	  el,
269	  elementsById,
270	  revision,
271	  onPersistProperty,
272	}: {
273	  el: Extract<Element, { kind: 'plan_view' }>;
274	  elementsById: Record<string, Element>;
275	  revision: number;
276	  onPersistProperty: (key: string, value: string) => void;
277	}): JSX.Element {
278	  const levels = (Object.values(elementsById) as Element[]).filter(
279	    (e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level',
280	  );
281	  const templates = (Object.values(elementsById) as Element[]).filter(
282	    (e): e is Extract<Element, { kind: 'view_template' }> => e.kind === 'view_template',
283	  );
284	
285	  const { t } = useTranslation();
286	  const pv = (key: string) => t(`inspector.planView.${key}`);
287	
288	  const [cropDraft, setCropDraft] = useState({
289	    minX: el.cropMinMm ? String(el.cropMinMm.xMm) : '',
290	    minY: el.cropMinMm ? String(el.cropMinMm.yMm) : '',
291	    maxX: el.cropMaxMm ? String(el.cropMaxMm.xMm) : '',
292	    maxY: el.cropMaxMm ? String(el.cropMaxMm.yMm) : '',
293	  });
294	
295	  return (
296	    <div className="space-y-2 text-[11px]">
297	      <label className={LABEL_CLS}>
298	        {pv('namePlaceholder')}
299	        <input
300	          className={INPUT_CLS}
301	          defaultValue={el.name}
302	          key={`pv-name-${el.id}-${el.name}-${revision}`}
303	          onBlur={(e) => {
304	            const v = e.target.value.trim();
305	            if (!v || v === el.name) return;
306	            onPersistProperty('name', v);
307	          }}
308	        />
309	      </label>
310	
311	      <label className={LABEL_CLS}>
312	        {pv('planPresentation')}
313	        <select
314	          className={INPUT_CLS}
315	          value={el.planPresentation ?? 'default'}
316	          onChange={(e) => onPersistProperty('planPresentation', e.target.value)}
317	        >
318	          <option value="default">{pv('neutralPresentation')}</option>
319	          <option value="opening_focus">{pv('openingFocus')}</option>
320	          <option value="room_scheme">{pv('roomScheme')}</option>
321	        </select>
322	      </label>
323	
324	      <label className={LABEL_CLS}>
325	        {pv('underlayLevel')}
326	        <select
327	          className={INPUT_CLS}
328	          value={el.underlayLevelId && levels.some((l) => l.id === el.underlayLevelId) ? el.underlayLevelId : ''}
329	          onChange={(e) => onPersistProperty('underlayLevelId', e.target.value)}
330	        >
331	          <option value="">{pv('none')}</option>
332	          {levels.map((l) => (
333	            <option key={l.id} value={l.id}>{l.name}</option>
334	          ))}
335	        </select>
336	      </label>
337	
338	      {templates.length > 0 ? (
339	        <>
340	          <label className={LABEL_CLS}>
341	            {pv('viewTemplateLink')}
342	            <select
343	              className={INPUT_CLS}
344	              value={el.viewTemplateId && templates.some((tmpl) => tmpl.id === el.viewTemplateId) ? el.viewTemplateId : ''}
345	              onChange={(e) => onPersistProperty('viewTemplateId', e.target.value)}
346	            >
347	              <option value="">{pv('none')}</option>
348	              {templates.map((tmpl) => (
349	                <option key={tmpl.id} value={tmpl.id}>{tmpl.name}</option>
350	              ))}
351	            </select>
352	          </label>
353	          <label className={LABEL_CLS}>
354	            {pv('applyTemplate')}
355	            <select
356	              className={INPUT_CLS}
357	              value=""
358	              onChange={(e) => {
359	                const tid = e.target.value;
360	                if (!tid) return;
361	                onPersistProperty('__applyTemplate__', JSON.stringify({ planViewId: el.id, templateId: tid }));
362	              }}
363	            >
364	              <option value="">{pv('selectToApply')}</option>
365	              {templates.map((tmpl) => (
366	                <option key={tmpl.id} value={tmpl.id}>{tmpl.name}</option>
367	              ))}
368	            </select>
369	          </label>
370	        </>
371	      ) : null}
372	
373	      <div className="border-t border-border pt-2 space-y-2">
374	        <div className="font-semibold text-muted">{pv('crop')}</div>
375	        <div className="grid grid-cols-2 gap-2">
376	          {(['minX', 'minY', 'maxX', 'maxY'] as const).map((k) => (
377	            <label key={k} className={LABEL_CLS}>
378	              {k}
379	              <input
380	                className={INPUT_CLS}
381	                value={cropDraft[k]}
382	                onChange={(e) => setCropDraft((d) => ({ ...d, [k]: e.target.value }))}
383	              />
384	            </label>
385	          ))}
386	        </div>
387	        <div className="flex gap-2">
388	          <button
389	            type="button"
390	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
391	            onClick={() => {
392	              const nx = Number(cropDraft.minX), ny = Number(cropDraft.minY);
393	              const xx = Number(cropDraft.maxX), xy = Number(cropDraft.maxY);
394	              if (![nx, ny, xx, xy].every(Number.isFinite)) return;
395	              onPersistProperty('cropMinMm', JSON.stringify({ xMm: nx, yMm: ny }));
396	              onPersistProperty('cropMaxMm', JSON.stringify({ xMm: xx, yMm: xy }));
397	            }}
398	          >
399	            {pv('applyCrop')}
400	          </button>
401	          <button
402	            type="button"
403	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
404	            onClick={() => {
405	              onPersistProperty('cropMinMm', '');
406	              onPersistProperty('cropMaxMm', '');
407	              setCropDraft({ minX: '', minY: '', maxX: '', maxY: '' });
408	            }}
409	          >
410	            {pv('clearCrop')}
411	          </button>
412	        </div>
413	      </div>
414	
415	      <div className="border-t border-border pt-2 space-y-2">
416	        <div className="font-semibold text-muted">{pv('viewRange')}</div>
417	        {(
418	          [
419	            { key: 'viewRangeBottomMm', label: pv('rangeBottom'), val: el.viewRangeBottomMm },
420	            { key: 'viewRangeTopMm', label: pv('rangeTop'), val: el.viewRangeTopMm },
421	            { key: 'cutPlaneOffsetMm', label: pv('cutPlaneOffset'), val: el.cutPlaneOffsetMm },
422	          ] as { key: string; label: string; val: number | null | undefined }[]
423	        ).map(({ key, label, val }) => (
424	          <label key={key} className={LABEL_CLS}>
425	            {label}
426	            <input
427	              className={INPUT_CLS}
428	              defaultValue={val == null ? '' : String(val)}
429	              key={`${key}-${el.id}-${val ?? 'null'}-${revision}`}
430	              placeholder={pv('emptyClearsPlaceholder')}
431	              inputMode="decimal"
432	              onBlur={(e) => onPersistProperty(key, e.target.value.trim())}
433	            />
434	          </label>
435	        ))}
436	      </div>
437	    </div>
438	  );
439	}
