441	/** Editable inspector for room elements (Properties tab). */
442	export function InspectorRoomEditor({
443	  el,
444	  revision,
445	  onPersistProperty,
446	}: {
447	  el: Extract<Element, { kind: 'room' }>;
448	  revision: number;
449	  onPersistProperty: (key: string, value: string) => void;
450	}): JSX.Element {
451	  const { t } = useTranslation();
452	  const f = (key: string) => t(`inspector.fields.${key}`);
453	  const r = (key: string) => t(`inspector.room.${key}`);
454	  const fields: { key: string; label: string; val: string | null | undefined; inputMode?: string }[] = [
455	    { key: 'name', label: f('name'), val: el.name },
456	    { key: 'programmeCode', label: r('programmeCode'), val: el.programmeCode },
457	    { key: 'department', label: f('department'), val: el.department },
458	    { key: 'functionLabel', label: r('functionLabel'), val: el.functionLabel },
459	    { key: 'finishSet', label: f('finishSet'), val: el.finishSet },
460	  ];
461	
462	  return (
463	    <div className="space-y-2 text-[11px]">
464	      {fields.map(({ key, label, val }) => (
465	        <label key={key} className={LABEL_CLS}>
466	          {label}
467	          <input
468	            className={INPUT_CLS}
469	            defaultValue={val ?? ''}
470	            key={`rm-${key}-${el.id}-${val ?? ''}-${revision}`}
471	            onBlur={(e) => {
472	              const v = e.target.value.trim();
473	              if (key === 'name' && (!v || v === val)) return;
474	              onPersistProperty(key, v);
475	            }}
476	          />
477	        </label>
478	      ))}
479	      <label className={LABEL_CLS}>
480	        {r('targetArea')}
481	        <input
482	          className={INPUT_CLS}
483	          defaultValue={el.targetAreaM2 == null ? '' : String(el.targetAreaM2)}
484	          key={`rm-tgt-${el.id}-${el.targetAreaM2 ?? 'x'}-${revision}`}
485	          placeholder={r('optional')}
486	          inputMode="decimal"
487	          onBlur={(e) => onPersistProperty('targetAreaM2', e.target.value.trim())}
488	        />
489	      </label>
490	      <FieldRow label={f('level')} value={el.levelId} mono />
491	      <FieldRow label={f('outlinePoints')} value={String(el.outlineMm.length)} />
492	    </div>
493	  );
494	}
