527	type CustomFamilyTypeElem = Extract<Element, { kind: 'family_type' }>;
528	
529	function CustomTypeForm({
530	  discipline,
531	  onSave,
532	  onCancel,
533	}: {
534	  discipline: 'door' | 'window';
535	  onSave: (baseFamilyId: string, name: string, params: Record<string, unknown>) => void;
536	  onCancel: () => void;
537	}): JSX.Element {
538	  const families = BUILT_IN_FAMILIES.filter((f) => f.discipline === discipline);
539	  const [baseFamilyId, setBaseFamilyId] = useState(families[0]?.id ?? '');
540	  const [name, setName] = useState('');
541	  const [paramDraft, setParamDraft] = useState<Record<string, string>>({});
542	
543	  const baseFam = getFamilyById(baseFamilyId);
544	  const lengthParams = baseFam?.params.filter((p) => p.type === 'length_mm') ?? [];
545	
546	  function handleSave(): void {
547	    const params: Record<string, unknown> = { name: name.trim(), baseFamilyId };
548	    for (const p of lengthParams) {
549	      const raw = paramDraft[p.key];
550	      const val = raw !== undefined ? Number(raw) : (p.default as number);
551	      if (Number.isFinite(val)) params[p.key] = val;
552	    }
553	    onSave(baseFamilyId, name.trim(), params);
554	  }
555	
556	  return (
557	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
558	      <label className={LABEL_CLS}>
559	        Base family
560	        <select
561	          className={INPUT_CLS}
562	          value={baseFamilyId}
563	          onChange={(e) => { setBaseFamilyId(e.target.value); setParamDraft({}); }}
564	        >
565	          {families.map((f) => <option key={f.id} value={f.id}>{f.name}</option>)}
566	        </select>
567	      </label>
568	      <label className={LABEL_CLS}>
569	        Type name
570	        <input
571	          className={INPUT_CLS}
572	          value={name}
573	          onChange={(e) => setName(e.target.value)}
574	          placeholder="e.g. Wide fire door"
575	          autoFocus
576	        />
577	      </label>
578	      {lengthParams.map((p) => (
579	        <label key={p.key} className={LABEL_CLS}>
580	          {p.label} (mm)
581	          <input
582	            className={INPUT_CLS}
583	            type="number"
584	            value={paramDraft[p.key] ?? String(p.default as number)}
585	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
586	          />
587	        </label>
588	      ))}
589	      <div className="flex gap-2 pt-0.5">
590	        <button
591	          type="button"
592	          disabled={!name.trim()}
593	          onClick={handleSave}
594	          className="flex-1 rounded border border-border bg-surface-strong px-2 py-0.5 text-[10px] hover:bg-accent-soft disabled:opacity-40"
595	        >
596	          Save type
597	        </button>
598	        <button
599	          type="button"
600	          onClick={onCancel}
601	          className="rounded border border-border px-2 py-0.5 text-[10px] hover:bg-surface-strong"
602	        >
603	          Cancel
604	        </button>
605	      </div>
606	    </div>
607	  );
